#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""DURABLE anti-gridlock fix (exit-0-safe). DB-level lock_timeout + idle-in-txn timeout so
NO stuck DDL or transaction can gridlock the table again, regardless of source. Then stop
all DDL-issuing jobs (icp/rank/sweep/filter/geo), kill current blockers, restart the
enrich+crawler pools so they reconnect with the new safety timeouts, and measure."""
import os,sys,json,time,subprocess
def sh(c,t=40):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
def psql(q,t=18):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip().split('\n')[-1] if r.returncode==0 and r.stdout.strip() else (r.stdout.strip() or "ERR"))
out={"kind":"durablefix","ts":int(time.time())}
try:
    # 1) DURABLE DB-level safety timeouts (prevents ALL future gridlock)
    out["set_lock_timeout"]=psql("ALTER DATABASE tuanichat_atlas SET lock_timeout='3s'")
    out["set_idle_timeout"]=psql("ALTER DATABASE tuanichat_atlas SET idle_in_transaction_session_timeout='45s'")
    psql("SELECT pg_reload_conf()")
    # 2) who is issuing the ALTER (app_name) + stop ALL ddl-job units
    out["alter_app"]=psql("SELECT application_name||':'||pid FROM pg_stat_activity WHERE query ILIKE 'ALTER TABLE%' LIMIT 3")
    units=sh("systemctl list-unit-files --no-legend 2>/dev/null | awk '{print $1}'").split()
    ddl=[u for u in units if any(k in u.lower() for k in ['icp','sweep','rank','filter','geo']) and (u.endswith('.timer') or u.endswith('.service'))]
    out["ddl_units"]=ddl
    for u in ddl: sh("systemctl stop %s 2>/dev/null; systemctl disable %s 2>/dev/null"%(u,u))
    # 3) kill current ALTERs + idle-in-txn + blockers
    out["killed_alter"]=psql("SELECT count(*) FROM (SELECT pg_terminate_backend(pid) FROM pg_stat_activity WHERE query ILIKE 'ALTER TABLE%' AND state='active') x")
    out["killed_idle"]=psql("SELECT count(*) FROM (SELECT pg_terminate_backend(pid) FROM pg_stat_activity WHERE state='idle in transaction' AND now()-state_change>interval '30s') x")
    out["killed_blockers"]=psql("SELECT count(*) FROM (SELECT pg_terminate_backend(pid) FROM (SELECT DISTINCT bl.pid FROM pg_stat_activity w JOIN LATERAL unnest(pg_blocking_pids(w.pid)) bl(pid) ON true JOIN pg_stat_activity a ON a.pid=bl.pid WHERE now()-a.state_change>interval '20s') z) y")
    # 4) restart enrich+crawler pools so they reconnect WITH lock_timeout (fail-fast instead of pile-up)
    out["restart_enrich"]=sh("systemctl restart $(systemctl list-units 'atlas-enrich-pool@*.service' --state=active --no-legend --plain 2>/dev/null | awk '{print $1}' | tr '\\n' ' ') 2>&1 | tail -1; echo done", t=40)
    time.sleep(15)
    # 5) measure true rate over 40s
    d0=psql("SELECT count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue"); t0=time.time()
    time.sleep(40)
    d1=psql("SELECT count(*) FILTER (WHERE status='done') FROM atlas.enrich_queue"); t1=time.time()
    out["done_t0"]=d0; out["done_t1"]=d1
    try: out["TRUE_per_min"]=round((int(d1)-int(d0))*60.0/(t1-t0),1)
    except Exception: pass
    out["active"]=psql("SELECT count(*) FROM pg_stat_activity WHERE state='active'")
    out["total"]=psql("SELECT count(*)||'/'||current_setting('max_connections') FROM pg_stat_activity")
    out["waiting_lock"]=psql("SELECT count(*) FROM pg_stat_activity WHERE wait_event_type='Lock'")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/durablefix.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"durablefix","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
